class Solution:
    def maxDistance(self, nums1, nums2):
        import bisect
        best = 0
        n2 = len(nums2)
        for i in range(len(nums1)):
            lo, hi = i, n2 - 1
            res = -1
            while lo <= hi:
                mid = (lo + hi) // 2
                if nums2[mid] >= nums1[i]:
                    res = mid
                    lo = mid + 1
                else:
                    hi = mid - 1
            if res >= 0:
                best = max(best, res - i)
        return best

