var maxDistance = function(nums1, nums2) {
    let i = 0, j = 0, best = 0;
    const n1 = nums1.length, n2 = nums2.length;
    while (i < n1 && j < n2) {
        if (nums1[i] > nums2[j]) i++;
        else { best = Math.max(best, j - i); j++; }
    }
    return best;
